INSERT INTO "public"."news" ("id", "title", "slug", "excerpt", "content", "cover_url", "tag", "status", "published_at", "author_id", "created_at", "updated_at") VALUES
	('817e54e9-4f0f-4f2d-9bb4-b0b694e57002', 'Pedra Bela ao nascer do sol: como foi o último rolê', 'pedra-bela-ao-nascer-do-sol-como-foi-o-ultimo-role', 'Acordamos antes do galo cantar pra pegar o nascer do sol no mirante. O frio compensou — e as fotos também.', '[{"id":"af893c78-60a1-4e81-a1f8-5d455cb8cd96","type":"paragraph","value":"Acordamos antes do galo cantar pra pegar o nascer do sol no mirante. O frio compensou — e as fotos também.\nUma experiência inesquecível para todos os membros."},{"id":"ac41fbed-50ce-47af-98b7-98a9a439e2f9","type":"image","value":"https://electrosal-erp-media.s3.us-east-2.amazonaws.com/motoclube/572f04af-39dd-4c96-9a31-af41c30befac-WhatsApp Image 2026-06-24 at 21.42.59.jpeg"}]', 'https://electrosal-erp-media.s3.us-east-2.amazonaws.com/motoclube/20be326d-cca8-40ee-8f62-0db5f6dca7d3-Melhorar foto - padrão motociclista(4).jpg', 'Bastidores', 'published', '2024-07-15 00:00:00+00', NULL, '2026-06-24 21:12:33.189585+00', '2026-06-25 01:12:16.065826+00'),
	('12a25e0d-0e9f-4670-b0e6-19b5dcfb56ed', 'Rolê a Monte Verde reúne a turma na serra', 'role-monte-verde-reune-a-turma-na-serra', 'Saída cedo de Atibaia, parada estratégica pra café e um dia inteiro curtindo as curvas da serra. Foi rolê pra entrar pra história do clube.', '[{"id":"b597d665-543f-4ee9-bd57-d9bb1d413e6e","type":"subtitle","value":"A chegada em Monte Verde"},{"id":"8312803e-66ac-48bb-88d6-bf3d65127a29","type":"paragraph","value":"Saída cedo de Atibaia, parada estratégica pra café e um dia inteiro curtindo as curvas da serra. Foi rolê pra entrar pra história do clube.\n\nMais detalhes em breve..."},{"id":"3354212e-0377-4896-b55c-45a4db94c68c","type":"image","value":"https://electrosal-erp-media.s3.us-east-2.amazonaws.com/motoclube/46faad3f-7f44-4b77-8c4f-20f1508e1da8-Melhorar foto - padrão motociclista(1).jpg"},{"id":"1de2663e-22a3-444f-aa61-9c481aac9ae3","type":"subtitle","value":"O Cafe da manhã"},{"id":"af0b0ac3-968a-4b3b-be8b-cdb18e1bedea","type":"image","value":"https://electrosal-erp-media.s3.us-east-2.amazonaws.com/motoclube/a4f5d129-3781-4610-9815-1dbe649611ed-Melhorar foto - padrão motociclista(3).jpg"},{"id":"a9be3c4b-1b0b-4a1a-aab1-06f25b1a976e","type":"paragraph","value":"Café da manhã em um lugarzinho fantastico, tudo muito gostoso..."}]', 'https://electrosal-erp-media.s3.us-east-2.amazonaws.com/motoclube/2ab78fc0-922d-4bf2-9471-4000c3548dde-Melhorar foto - padrão motociclista.jpg', 'Passeio', 'published', '2026-03-19 00:00:00+00', NULL, '2026-06-24 21:12:33.189585+00', '2026-06-25 11:56:06.341972+00'),
	('662dcf8a-99a3-471f-96b5-87b8f0cf842b', 'Passeio Salesopolis - Rota Biker monumento 19', 'salesopolis', 'Em Salesópolis (SP), o monumento oficial da Rota Biker fica no Rancho Terra Crua (Monumento nº 19). O local oferece estrutura de lazer, restaurante e é um ponto de encontro famoso para motociclistas.', '[{"id":"1f0ed019-b3fc-4b8d-a023-805f2a319f78","type":"subtitle","value":"Duas Rodas e Histórias: Nossa Jornada até o Monumento 19 em Salesópolis"},{"id":"af4deea0-abf8-4ea3-93da-ae0fe08ec00a","type":"paragraph","value":"Para quem vive a cultura das duas rodas, o final de semana não é apenas um descanso, é o momento de colocar o vento na cara e acumular novas histórias. Dessa vez, o destino escolhido foi Salesópolis, seguindo pela famosa Rota Biker com destino ao emblemático Monumento 19.\nSe você curte poeira, belas paisagens e a resenha boa que só o motociclismo proporciona, acompanha como foi essa nossa jornada.\nO Ponto de Partida: O Despertar dos Motores\nO dia começou cedo. Às 07h da manhã, o ponto de encontro já estava definido: o Posto Jardim dos Pinheiros. À medida que os relógios se aproximavam do horário, o ronco dos motores começava a quebrar o silêncio da manhã. Abraços, ajustes finos nos equipamentos e tanques cheios. Era hora de partir."},{"id":"d01e253e-7b5c-491e-aab8-65e5f52ba160","type":"paragraph","value":"Parada Obrigatória: Café da Manhã no Rancho da Moto\n\nTodo bom motociclista sabe que o caminho é tão importante quanto o destino, e uma parada para o café é sagrada. Seguimos rodando até o Rancho da Moto.\nAo chegar lá, uma surpresa: o lugar estava completamente lotado! O pátio era um verdadeiro mar de motos de todos os estilos e cilindradas. Mesmo com o movimento intenso e a casa cheia, o clima era de pura camaradagem. Conseguimos encostar, tomar aquele café reforçado para dar energia e, claro, jogar muita conversa fora com a galera. O ambiente do Rancho nunca decepciona; a energia de ver tanta gente compartilhando a mesma paixão torna tudo muito agradável."},{"id":"2c818cca-187f-4643-a61b-e2be0ddfacf9","type":"image","value":"https://electrosal-erp-media.s3.us-east-2.amazonaws.com/motoclube/00e28f3f-4a42-4cb4-a93b-6d6132afe1e0-WhatsApp Image 2026-06-26 at 13.57.37.jpeg"},{"id":"66943d68-aa77-4dc8-929c-1bb57adebdaf","type":"paragraph","value":"O Desafio e a Recompensa: Monumento 19\nDe barriga cheia e alma renovada, pegamos a estrada novamente rumo ao objetivo principal: o Monumento 19.\nPor ser um ponto clássico e muito visado por quem faz a Rota Biker, sabíamos que não estaríamos sozinhos. Quando chegamos, nos deparamos com uma fila de cerca de 1 hora para conseguir acessar e registrar o momento.\n    A filosofia da estrada: Para o verdadeiro biker, a espera não é um problema, mas sim parte da resenha.\nAproveitamos o tempo de fila para conversar, rir das histórias do caminho e planejar os próximos destinos. Quando finalmente chegou a nossa vez, valeu cada minuto. O visual e a energia do lugar são incríveis. Registramos o momento com muitas fotos — daquelas que vão direto para o grupo da família e para as redes sociais para eternizar o final de semana.\nMoto Turismo na Essência\nNo fim das contas, passeios como esse nos lembram o porquê de gostarmos tanto de motos. Não se trata apenas da velocidade ou do destino final, mas sim das parcerias, da paciência na fila, do café compartilhado e das memórias que ficam guardadas na bagagem da vida.\nSalesópolis e a Rota Biker entregaram tudo o que prometiam. Até o próximo acelerada!\n\nE você, já fez a Rota Biker até o Monumento 19? Como estava a fila no seu dia? Deixe seu comentário!"},{"id":"db813896-c68a-418f-a5c0-ea7de1f41350","type":"image","value":"https://electrosal-erp-media.s3.us-east-2.amazonaws.com/motoclube/26c62d68-5f66-437b-82ae-8ddf92ee6095-1.jpg"}]', 'https://electrosal-erp-media.s3.us-east-2.amazonaws.com/motoclube/580cefe6-a71a-49f2-a286-2b768f0f9059-2.jpg', 'Passeio', 'published', '2026-06-21 00:00:00+00', NULL, '2026-06-26 17:13:38.485622+00', '2026-06-26 17:32:37.454777+00');
