INSERT INTO "public"."routes" ("id", "title", "description", "destination", "start_date", "meeting_point", "meeting_time", "estimated_distance_km", "waze_url", "media_url", "created_at", "created_by", "status", "estimated_duration_mins", "visited_places", "route_type", "has_financial_plan") VALUES
	('0ec44b75-b822-4477-a22f-4cd0eb66b585', 'Passeio de Pedra Bela', 'Pedra Bela é uma pequena e charmosa cidade no interior de São Paulo. Fica na Serra da Mantiqueira, a cerca de 1.120 metros de altitude. É muito famosa pela Mega Tirolesa, considerada uma das maiores do mundo, e pelo seu clima agradável de montanha.', 'Pedra Bela - SP', '2024-07-14 10:00:00+00', 'Posto Pedra Grande', '07:00:00', 62, 'https://ul.waze.com/ul?place=ChIJRW9AroVLyZQRwHi7qU6q_18&ll=-22.79479840%2C-46.44335750&navigate=yes&utm_campaign=default&utm_source=waze_website&utm_medium=lm_share_location', NULL, '2026-06-25 13:51:28.001654+00', NULL, 'completed', 120, 'Pedra Bela', 'passeio', false),
	('2c887b2d-a964-461b-854f-3bf30ab87f68', 'Monte Verde', 'Monte Verde é um charmoso distrito de Camanducaia (MG), localizado a cerca de 160 km de São Paulo. Conhecida como a "Suíça Mineira", a cidade é famosa pelo clima frio, arquitetura europeia e romantismo. É o destino perfeito para casais e amantes da natureza.', 'Monte Verde - MG', '2026-03-18 10:00:00+00', 'Posto Pedra Grande', '07:00:00', 104, 'https://ul.waze.com/ul?place=ChIJ1QdTET4QzJQROiVu16xnmgA&ll=-22.86268810%2C-46.03646040&navigate=yes&utm_campaign=default&utm_source=waze_website&utm_medium=lm_share_location', NULL, '2026-06-25 18:18:22.141234+00', NULL, 'completed', 120, 'Monte Verde', 'passeio', false),
	('d1a5767d-74df-4189-a711-d1fa6709af4a', 'Passeio Joanopolis', 'Joanópolis é uma cidade turística na Serra da Mantiqueira, a cerca de 120 km de São Paulo. Conhecida como a "Capital do Lobisomem", é famosa pela Cachoeira dos Pretos (segunda maior do estado, com 154 metros) e pelas trilhas, turismo rural e comida caipira.', 'Joanopolis', '2026-05-03 10:00:00+00', 'Posto Jd dos Pinheiros', '07:00:00', 70, 'https://www.waze.com/live-map/directions/cachoeira-dos-pretos-est.-para-a-cachoeira-joanopolis?to=place.w.205653538.2056731992.7001416&from=place.w.205391393.2054110536.255591&utm_medium=lm_share_directions&utm_campaign=default&utm_source=waze_website', NULL, '2026-06-25 18:24:38.08297+00', NULL, 'completed', 80, 'Cacheora dos Pretos', 'passeio', false),
	('10bf12af-0205-4a42-bf2c-02792877a460', 'Passeio Salesopolis', 'Salesópolis abriga o Monumento Rota Biker número 19, localizado no Rancho Terra Crua. Ele fica às margens da Represa do Rio Paraitinga. Os motociclistas costumam chegar a partir de São Paulo ou do Alto Tietê pela Rodovia SP-088, passando por Santa Branca.', 'Salesópolis abriga o Monumento Rota Biker número 19', '2026-06-21 10:00:00+00', 'Posto Jd dos Pinheiros', '07:00:00', 120, 'https://ul.waze.com/ul?place=ChIJywLkHAC_zZQR8zdfNg7FZp4&ll=-23.52126190%2C-45.89830790&navigate=yes&utm_campaign=default&utm_source=waze_website&utm_medium=lm_share_location', NULL, '2026-06-25 18:34:30.911893+00', NULL, 'completed', 120, NULL, 'passeio', false),
	('88408c00-e8a2-472b-ad01-867f86fed2b1', 'Viagem Santa Catarina', 'Planejamento Viagem Santa catarina', 'Santa Catarina - SC', '2026-10-30 20:49:00+00', 'em aberto', '09:00:00', NULL, NULL, NULL, '2026-07-02 17:53:01.417378+00', NULL, 'planning', NULL, 'Urubici', 'viagem', true),
